import { useState, useRef, useEffect, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';

interface NowPlaying {
  artist: string;
  title: string;
  listeners: number;
  bitrate: number;
  genre: string;
}

const STREAM_URL = '/icecast/live'; // Proxied through nginx
const QUALITIES = [
  { label: 'High (192k)', url: '/icecast/live' },
  { label: 'Medium (128k)', url: '/icecast/live-128' },
  { label: 'Low (64k)', url: '/icecast/live-64' },
];

export default function RadioPlayer() {
  const audioRef = useRef<HTMLAudioElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.8);
  const [isMuted, setIsMuted] = useState(false);
  const [quality, setQuality] = useState(QUALITIES[0]);
  const [nowPlaying, setNowPlaying] = useState<NowPlaying | null>(null);
  const [socketConnected, setSocketConnected] = useState(false);

  useEffect(() => {
    const socket: Socket = io('/radio', { transports: ['websocket'] });
    socket.on('connect', () => setSocketConnected(true));
    socket.on('disconnect', () => setSocketConnected(false));
    socket.on('now_playing', (data: NowPlaying) => setNowPlaying(data));
    return () => { socket.disconnect(); };
  }, []);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  const togglePlay = useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying) {
      audio.pause();
      audio.src = '';
      setIsPlaying(false);
    } else {
      audio.src = quality.url;
      audio.play().then(() => setIsPlaying(true)).catch(console.error);
    }
  }, [isPlaying, quality]);

  const handleQualityChange = (q: typeof QUALITIES[number]) => {
    setQuality(q);
    if (isPlaying && audioRef.current) {
      audioRef.current.src = q.url;
      audioRef.current.play().catch(console.error);
    }
  };

  return (
    <div className="radio-player">
      <audio ref={audioRef} preload="none" />

      <div className="now-playing">
        {nowPlaying ? (
          <>
            <span className="artist">{nowPlaying.artist}</span>
            <span className="separator"> &mdash; </span>
            <span className="track-title">{nowPlaying.title}</span>
            <span className="listeners">{nowPlaying.listeners} listeners</span>
          </>
        ) : (
          <span className="offline">Connecting...</span>
        )}
      </div>

      <div className="controls">
        <button onClick={togglePlay} className="play-btn">
          {isPlaying ? 'Stop' : 'Play'}
        </button>

        <button onClick={() => setIsMuted(!isMuted)} className="mute-btn">
          {isMuted ? 'Unmute' : 'Mute'}
        </button>

        <input
          type="range" min={0} max={1} step={0.01}
          value={isMuted ? 0 : volume}
          onChange={e => { setVolume(parseFloat(e.target.value)); setIsMuted(false); }}
          className="volume-slider"
        />

        <select
          value={quality.label}
          onChange={e => {
            const q = QUALITIES.find(q => q.label === e.target.value);
            if (q) handleQualityChange(q);
          }}
        >
          {QUALITIES.map(q => (
            <option key={q.label} value={q.label}>{q.label}</option>
          ))}
        </select>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Socket } from 'socket.io-client';

interface ChatMessage {
  name: string;
  message: string;
  time: string;
}

interface SongRequest {
  id: number;
  name: string;
  artist: string;
  title: string;
  votes?: number;
  time: string;
}

interface Props {
  socket: Socket;
  listenerName: string;
}

export default function ListenerChat({ socket, listenerName }: Props) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [requests, setRequests] = useState<SongRequest[]>([]);
  const [input, setInput] = useState('');
  const [reqArtist, setReqArtist] = useState('');
  const [reqTitle, setReqTitle] = useState('');
  const [tab, setTab] = useState<'chat' | 'requests'>('chat');
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    socket.on('chat_history', (history: ChatMessage[]) => setMessages(history));
    socket.on('new_message', (msg: ChatMessage) =>
      setMessages(prev => [...prev.slice(-200), msg])
    );
    socket.on('request_received', (req: SongRequest) =>
      setRequests(prev => [req, ...prev].slice(0, 50))
    );
    socket.on('vote_updated', (data: { id: number; votes: number }) =>
      setRequests(prev =>
        prev.map(r => r.id === data.id ? { ...r, votes: data.votes } : r)
      )
    );
    return () => {
      socket.off('chat_history');
      socket.off('new_message');
      socket.off('request_received');
      socket.off('vote_updated');
    };
  }, [socket]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = () => {
    if (!input.trim()) return;
    socket.emit('send_message', { name: listenerName, message: input });
    setInput('');
  };

  const submitRequest = () => {
    if (!reqArtist.trim() || !reqTitle.trim()) return;
    socket.emit('song_request', {
      name: listenerName, artist: reqArtist, title: reqTitle
    });
    setReqArtist('');
    setReqTitle('');
  };

  return (
    <div className="listener-chat">
      <div className="chat-tabs">
        <button className={tab === 'chat' ? 'active' : ''} onClick={() => setTab('chat')}>Chat</button>
        <button className={tab === 'requests' ? 'active' : ''} onClick={() => setTab('requests')}>Requests</button>
      </div>

      {tab === 'chat' ? (
        <>
          <div className="chat-messages">
            {messages.map((msg, i) => (
              <div key={i} className="chat-msg">
                <strong>{msg.name}:</strong> {msg.message}
                <time>{new Date(msg.time).toLocaleTimeString()}</time>
              </div>
            ))}
            <div ref={bottomRef} />
          </div>
          <div className="chat-input">
            <input value={input} onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && sendMessage()}
              placeholder="Type a message..." maxLength={500} />
            <button onClick={sendMessage}>Send</button>
          </div>
        </>
      ) : (
        <>
          <div className="request-list">
            {requests.map(req => (
              <div key={req.id} className="song-request">
                <span className="req-song">{req.artist} - {req.title}</span>
                <span className="req-by">by {req.name}</span>
                <button onClick={() => socket.emit('vote_request', { request_id: req.id })}>
                  +1 ({req.votes || 0})
                </button>
              </div>
            ))}
          </div>
          <div className="request-form">
            <input value={reqArtist} onChange={e => setReqArtist(e.target.value)}
              placeholder="Artist" maxLength={120} />
            <input value={reqTitle} onChange={e => setReqTitle(e.target.value)}
              placeholder="Song title" maxLength={200}
              onKeyDown={e => e.key === 'Enter' && submitRequest()} />
            <button onClick={submitRequest}>Request</button>
          </div>
        </>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';

interface ScheduleSlot {
  title: string;
  slug: string;
  genre: string;
  cover_image_url: string | null;
  dj_name: string | null;
  dj_avatar: string | null;
  start_time: string;
  end_time: string;
}

interface ScheduleData {
  [day: string]: ScheduleSlot[];
}

const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

export default function ShowSchedule() {
  const [schedule, setSchedule] = useState<ScheduleData>({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('/api/shows/schedule')
      .then(r => r.json())
      .then(data => { setSchedule(data.schedule); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const now = new Date();
  const todayName = DAYS[now.getDay() === 0 ? 6 : now.getDay() - 1];
  const currentTime = now.toTimeString().slice(0, 5);

  const isCurrentSlot = (day: string, slot: ScheduleSlot) =>
    day === todayName && slot.start_time <= currentTime && slot.end_time > currentTime;

  if (loading) return <div>Loading schedule...</div>;

  return (
    <div className="schedule-grid">
      {DAYS.map(day => (
        <div key={day} className={`schedule-day ${day === todayName ? 'today' : ''}`}>
          <h3>{day}</h3>
          {(schedule[day] || []).map((slot, i) => (
            <div key={i} className={`schedule-slot ${isCurrentSlot(day, slot) ? 'on-air' : ''}`}>
              <span className="slot-time">{slot.start_time} - {slot.end_time}</span>
              <span className="slot-title">{slot.title}</span>
              <span className="slot-genre">{slot.genre}</span>
              {slot.dj_name && <span className="slot-dj">with {slot.dj_name}</span>}
            </div>
          ))}
          {!(schedule[day] || []).length && (
            <div className="schedule-slot empty">AutoDJ all day</div>
          )}
        </div>
      ))}
    </div>
  );
}

import { useEffect } from 'react';

interface MediaSessionOptions {
  title: string;
  artist: string;
  album?: string;
  artworkUrl?: string;
  onPlay: () => void;
  onPause: () => void;
  onStop: () => void;
}

export function useMediaSession(opts: MediaSessionOptions) {
  useEffect(() => {
    if (!('mediaSession' in navigator)) return;

    navigator.mediaSession.metadata = new MediaMetadata({
      title: opts.title,
      artist: opts.artist,
      album: opts.album || 'My Online Radio',
      artwork: opts.artworkUrl
        ? [{ src: opts.artworkUrl, sizes: '512x512', type: 'image/png' }]
        : [],
    });

    navigator.mediaSession.setActionHandler('play', opts.onPlay);
    navigator.mediaSession.setActionHandler('pause', opts.onPause);
    navigator.mediaSession.setActionHandler('stop', opts.onStop);

    return () => {
      navigator.mediaSession.setActionHandler('play', null);
      navigator.mediaSession.setActionHandler('pause', null);
      navigator.mediaSession.setActionHandler('stop', null);
    };
  }, [opts.title, opts.artist, opts.artworkUrl]);
}

const CACHE_NAME = 'radio-shell-v1';
const SHELL_URLS = [
  '/',
  '/index.html',
  '/manifest.json',
  '/icons/icon-192.png',
  '/icons/icon-512.png',
];

self.addEventListener('install', (event: ExtendableEvent) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then(cache => cache.addAll(SHELL_URLS))
  );
});

self.addEventListener('activate', (event: ExtendableEvent) => {
  event.waitUntil(
    caches.keys().then(keys =>
      Promise.all(
        keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k))
      )
    )
  );
});

self.addEventListener('fetch', (event: FetchEvent) => {
  const url = new URL(event.request.url);

  // Never cache the audio stream or API calls
  if (url.pathname.startsWith('/icecast') ||
      url.pathname.startsWith('/api') ||
      url.pathname.startsWith('/socket.io')) {
    return;
  }

  event.respondWith(
    caches.match(event.request).then(cached =>
      cached || fetch(event.request).then(response => {
        if (response.ok && event.request.method === 'GET') {
          const clone = response.clone();
          caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
        }
        return response;
      })
    )
  );
});
